module adder8 (
    input [7:0] A,
    input [7:0] B,
    output [7:0] S,
    output C
);

    wire [7:0] sum;
    wire [7:0] obf_carry;

    assign sum[0] = A[0] ^ B[0];
    assign obf_carry[0] = A[0] & B[0];

    genvar i;
    generate
        for (i = 1; i < 8; i = i + 1) begin : adder_loop
            assign sum[i] = A[i] ^ B[i] ^ obf_carry[i-1];
            assign obf_carry[i] = (A[i] & B[i]) | (A[i] & obf_carry[i-1]) | (B[i] & obf_carry[i-1]);
        end
    endgenerate

    assign S = sum;
    assign C = obf_carry[7];

endmodule
